import{_ as t,o,c as r,a2 as i}from"./chunks/framework.BWuWLRhz.js";const h=JSON.parse('{"title":"Sovereign repositories","description":"","frontmatter":{},"headers":[],"relativePath":"repositories.md","filePath":"repositories.md"}'),s={name:"repositories.md"};function a(n,e,d,l,p,c){return o(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="sovereign-repositories" tabindex="-1">Sovereign repositories <a class="header-anchor" href="#sovereign-repositories" aria-label="Permalink to &quot;Sovereign repositories&quot;">​</a></h1><p>Sovereign uses a small set of first-party repositories. This page is the canonical map for what each repository owns, whether it is active or archived, and which docs should point to it.</p><h2 id="core-repositories" tabindex="-1">Core repositories <a class="header-anchor" href="#core-repositories" aria-label="Permalink to &quot;Core repositories&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Repository</th><th>Status</th><th>Purpose</th></tr></thead><tbody><tr><td><a href="https://github.com/sovereignfs/sovereign" target="_blank" rel="noreferrer"><code>sovereignfs/sovereign</code></a></td><td>Active</td><td>Primary platform repository: runtime, auth app, packages, built-in platform plugins, docs, RFCs, and roadmap.</td></tr><tr><td><a href="https://github.com/sovereignfs/sovereign-legacy" target="_blank" rel="noreferrer"><code>sovereignfs/sovereign-legacy</code></a></td><td>Archived</td><td>Previous Sovereign codebase. Kept for historical reference and migration context only; new work happens in <code>sovereignfs/sovereign</code>.</td></tr></tbody></table><h2 id="plugin-repositories" tabindex="-1">Plugin repositories <a class="header-anchor" href="#plugin-repositories" aria-label="Permalink to &quot;Plugin repositories&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Repository</th><th>Status</th><th>Purpose</th></tr></thead><tbody><tr><td><a href="https://github.com/sovereignfs/sovereign-plugin-template" target="_blank" rel="noreferrer"><code>sovereignfs/sovereign-plugin-template</code></a></td><td>Active template</td><td>Canonical standalone plugin starter repository. Use this when creating a plugin outside the monorepo.</td></tr><tr><td><a href="https://github.com/sovereignfs/sovereign-plugins-examples" target="_blank" rel="noreferrer"><code>sovereignfs/sovereign-plugins-examples</code></a></td><td>Active</td><td>Example plugins demonstrating basic, API provider, minimal shell, monetized, and overlay app patterns. The platform bundles these at build/install time as hidden-by-default examples.</td></tr><tr><td><a href="https://github.com/sovereignfs/sovereign-tasks" target="_blank" rel="noreferrer"><code>sovereignfs/sovereign-tasks</code></a></td><td>Active</td><td>Default bundled Tasks plugin. It is a real product plugin, visible from first boot, and versioned independently of the platform.</td></tr><tr><td><a href="https://github.com/sovereignfs/sovereign-plainwrite" target="_blank" rel="noreferrer"><code>sovereignfs/sovereign-plainwrite</code></a></td><td>Active</td><td>Default bundled Plainwrite plugin — a git-backed content editor for static site generators. It is a real product plugin, visible from first boot, and versioned independently of the platform.</td></tr></tbody></table><h2 id="documentation-and-deployment-support" tabindex="-1">Documentation and deployment support <a class="header-anchor" href="#documentation-and-deployment-support" aria-label="Permalink to &quot;Documentation and deployment support&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Repository</th><th>Status</th><th>Purpose</th></tr></thead><tbody><tr><td><a href="https://github.com/sovereignfs/storybook" target="_blank" rel="noreferrer"><code>sovereignfs/storybook</code></a></td><td>Active deployment target</td><td>GitHub Pages repository for the built <code>@sovereignfs/ui</code> Storybook static site, served at <a href="https://sovereignfs.github.io/storybook/" target="_blank" rel="noreferrer"><code>sovereignfs.github.io/storybook</code></a>. Source stories live in this primary repository under <code>packages/ui</code>.</td></tr><tr><td><a href="https://github.com/sovereignfs/sovereign-infra" target="_blank" rel="noreferrer"><code>sovereignfs/sovereign-infra</code></a></td><td>Active template</td><td>Operator-owned self-hosting template for Ubuntu VPS deployments: Caddy, Docker Compose, age-encrypted <code>.env</code> files, matching-tag deploys of official Sovereign images, and GitHub Actions CI/CD. No Terraform or managed-cloud dependency.</td></tr><tr><td><a href="https://github.com/sovereignfs/sovereignfs.github.io" target="_blank" rel="noreferrer"><code>sovereignfs/sovereignfs.github.io</code></a></td><td>Active deployment target</td><td>GitHub Pages repository for the public VitePress docs site at <a href="https://sovereignfs.github.io/" target="_blank" rel="noreferrer"><code>sovereignfs.github.io</code></a>. Source docs live in this primary repository under <code>docs/</code>.</td></tr></tbody></table><h2 id="naming-notes" tabindex="-1">Naming notes <a class="header-anchor" href="#naming-notes" aria-label="Permalink to &quot;Naming notes&quot;">​</a></h2><ul><li>Use <code>sovereignfs/sovereign-plugins-examples</code>, not <code>sovereign-examples</code>.</li><li>Use <code>sovereignfs/sovereign-tasks</code>, not <code>sovereign-plugin-tasks</code>.</li><li>Use <code>sovereignfs/sovereign-plainwrite</code>, not <code>sovereign-plugin-plainwrite</code>.</li><li><code>sovereignfs/storybook</code> and <code>sovereignfs/sovereignfs.github.io</code> are deployment targets. Edit source stories and docs in <code>sovereignfs/sovereign</code>.</li><li><code>sovereignfs/sovereign-infra</code> is a template that operators fork or use as a GitHub template. The platform repository publishes release images; the operator&#39;s infra repository controls when those images are deployed to the operator&#39;s VPS.</li><li>Historical planning docs may mention older candidate repositories such as Splitify, API Composer, or PaperTrail. They are not part of the current support-repository set unless this page is updated.</li></ul>',10)])])}const f=t(s,[["render",a]]);export{h as __pageData,f as default};
